-- Before optimization: query takes 8 seconds on 10M rows
SELECT * FROM orders WHERE customer_id = 12345 AND status = 'complete';

-- Step 1: Check the query plan
EXPLAIN QUERY PLAN SELECT * FROM orders WHERE customer_id = 12345;
-- Output: SCAN TABLE orders (full scan = slow!)

-- Step 2: Add the right index
CREATE INDEX idx_orders_customer_status ON orders(customer_id, status);

-- Step 3: Verify (now uses index)
EXPLAIN QUERY PLAN SELECT * FROM orders WHERE customer_id = 12345;
-- Output: SEARCH TABLE orders USING INDEX (fast!)

import sqlite3

# BAD: swallows all errors silently
try:
    conn = sqlite3.connect(db_path)
except:
    pass  # nothing works, nobody knows why

# BAD: catches everything, generic message
try:
    conn = sqlite3.connect(db_path)
except Exception as e:
    print(f"Error: {e}")

# GOOD: specific, actionable error messages
try:
    conn = sqlite3.connect(db_path)
except FileNotFoundError:
    print(f"Database not found at: {db_path}")
    print("Check that the path is correct and the file exists.")
    raise  # re-raise so the caller knows it failed
except sqlite3.OperationalError as e:
    print(f"Database connection failed: {e}")
    print("The database may be locked or corrupted.")
    raise
